import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ChargeMaintenanceService } from 'src/app/shared/services/charge-maintenance-service.service';
import { MaintenanceService } from 'src/app/shared/services/maintenance.service';
import { RoleService } from 'src/app/shared/services/role.service';

@Component({
  selector: 'npr-department-id-maintenance',
  templateUrl: './department-id-maintenance.component.html',
  styleUrls: ['./department-id-maintenance.component.scss'],
})
export class DepartmentIdMaintenanceComponent implements OnInit {
  respArray: any[] = [];
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];

  constructor(
    private apiService: MaintenanceService,
    private router: Router,
    private roleService: RoleService
  ) {}

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      // columnDefs: [ { type: 'date', 'targets': ['inputTime'] } ],
      // order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, -1],
        [5, 10, 20, 30],
      ],
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
    };
    this.getChargeMaintainenceSummary();
    this.roleService.fetchScreenPermissions('Department ID Maintenance');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }

  getChargeMaintainenceSummary() {
    this.isLoading = true;
    this.apiService
      .gettingDepartmentDataInSummary()
      .subscribe((dataresp: any) => {
        for (let item of dataresp.result) {
          item.verifiedStatus = this.statusArr.find((i) =>
            i.startsWith(item.verifiedStatus)
          );
        }
        this.respArray = dataresp.result;
        this.isLoading = false;

        this.dtTrigger.next();
      });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }
  new() {
    localStorage.removeItem('idValue');
    this.apiService.setIndex({
      index: '',
    });
    this.router.navigateByUrl(
      '/system-param-maintenance/dept-id-maintenance-new'
    );
  }
  edit(data) {
    this.apiService.setIndex({
      index: data.departId,
    });
    localStorage.setItem('idValue', data.departId);
    this.router.navigateByUrl(
      '/system-param-maintenance/dept-id-maintenance-new'
    );
  }
}
